 93→    abstract static class TreeNodeMixin<T extends RelIdProvider> {
 94→        @JsonProperty("children")
 95→        @JsonDeserialize(contentAs = TreeNode.class)
 96→        abstract List<TreeNode<T>> getChildren();
 97→
 98→        @JsonProperty("children")
