102→    @RabbitListener(queues = SPACE_NODE_MIGRATION_QUEUE)
103→    public void handle(Message message, Channel channel) throws IOException {
104→        String body = new String(message.getBody());
105→        log.info("Received space node migration task message: {}", body);
106→
107→        SpaceNodeMigrationMessage messageDto = JSONUtil.toBean(body, SpaceNodeMigrationMessage.class);
108→        String taskId = messageDto.getTaskId();
109→
110→        try {
111→            SpaceNodeMigrationTaskEntity task = spaceNodeMigrationTaskService.getByTaskId(taskId);
112→            ExceptionUtil.isNotNull(task, DatabaseException.QUERY_EMPTY_BY_ID);
113→            task.setStatus(SpaceNodeMigrationTaskStatusEnum.PROCESSING.getValue());
114→            spaceNodeMigrationTaskService.updateById(task);
115→
116→            executeTask(task);
117→
118→            task.setStatus(SpaceNodeMigrationTaskStatusEnum.COMPLETED.getValue());
119→            spaceNodeMigrationTaskService.updateById(task);
120→
121→        } catch (Exception e) {
122→            log.error("Failed to process space node migration task: taskId={}, error={}", taskId, e.getMessage(), e);
123→            SpaceNodeMigrationTaskEntity task = spaceNodeMigrationTaskService.getByTaskId(taskId);
124→            if (task != null) {
125→                task.setStatus(SpaceNodeMigrationTaskStatusEnum.FAILED.getValue());
126→                task.setErrorMessage(e.getMessage());
127→                spaceNodeMigrationTaskService.updateById(task);
128→            }
129→        } finally {
130→            // 先不考虑重试
131→            long deliveryTag = message.getMessageProperties().getDeliveryTag();
132→            channel.basicAck(deliveryTag, false);
133→        }
134→    }
135→
136→    private void executeTask(SpaceNodeMigrationTaskEntity task) throws IOException {
137→        UserSimpleInfoVo user = apitableGrpcClientService.getUserByEmail(task.getEmail());
138→        ExceptionUtil.isNotNull(user, SpaceNodeMigrationException.OPERATOR_NOT_EXIST);
139→        Long userId = user.getId();
140→        // 鉴权
141→        if (!spaceQueryManager.isUserSpaceAdmin(userId, task.getTargetSpaceId())) {
142→            throw new BusinessException(AuthException.UNAUTHORIZED);
143→        }
144→
145→        List<TreeNode<SpaceNodeVo>> spaceNodeTree = deserializeTree(task.getOriginTree());
146→        List<SpaceAppRelVo> sourceSpaceAppRels = JSONUtil.toList(task.getSourceSpaceAppRels(), SpaceAppRelVo.class);
147→        MigrationTypeEnum migrationType = MigrationTypeEnum.fromValue(task.getType());
148→
149→        log.info("executeTask: taskId={}, treeSize={}, type: {}, appRels: {}", task.getTaskId(), spaceNodeTree.size(), migrationType.getDescription(), task.getSourceSpaceAppRels());
150→
151→        MigrationConfig migrationConfig = MigrationConfig.builder()
152→                .email(task.getEmail())
153→                .sourceSpaceAppRels(sourceSpaceAppRels)
154→                .build();
155→        
156→        SpaceNodeMigrationResult overallResult = appMigrationChain.executeMigration(
157→                spaceNodeTree, 
158→                task.getTargetSpaceId(),
159→                task.getSourceSpaceId(),
160→                migrationType, 
161→                migrationConfig
162→        );
163→        
164→        log.info("Overall migration completed: success={}, failed={}, total mappings={}", 
165→                overallResult.getSuccessCount(), overallResult.getFailedCount(), 
166→                overallResult.getNodeIdMapping().size());
167→
168→        // 迁移中遇到错误抛异常并终止迁移
169→        if (overallResult.getErrorMessage() != null) {
170→            log.warn("Migration had errors: {}", overallResult.getErrorMessage());
171→            throw new BusinessException(overallResult.getErrorMessage());
172→        }
173→
174→        // 迁移后的节点重新构建成树并入库
175→        saveNewNodeTree(spaceNodeTree, task.getTargetSpaceId(), overallResult.getNodeIdMapping(), userId,
176→                task.getSourceSpaceId(), migrationType, migrationConfig);
177→        // 判断是空间站内迁移并且保留状态是false，调用文件删除接口，把源文件删除
178→        if (!task.getIsRemained() && task.getType().equals(MigrationTypeEnum.INTRA_SERVER.getValue())) {
179→            for (TreeNode<SpaceNodeVo> treeNode : spaceNodeTree) {
180→                // 清理源文件的版本快照
181→                versionSnapshotService.disableByNodeId(treeNode.getRelId());
182→                spaceNodeUpdateManager.deleteSpaceNode(treeNode.getRelId(), userId);
183→            }
184→        }
185→    }
