187→    private void saveNewNodeTree(List<TreeNode<SpaceNodeVo>> originalTree, String spaceId, Map<String, String> nodeIdMapping,
188→                                  Long userId, String sourceSpaceId, MigrationTypeEnum migrationType, MigrationConfig migrationConfig) {
189→        if (originalTree == null || originalTree.isEmpty()) {
190→            log.info("No tree nodes to save for space: {}", spaceId);
191→            return;
192→        }
193→
194→        log.info("Starting to save new node tree for space: {}, total original nodes: {}", spaceId, originalTree.size());
195→
196→        for (TreeNode<SpaceNodeVo> node : originalTree) {
197→            saveNodeAndChildren(node, spaceId, nodeIdMapping, ROOT_PARENT_ID, userId,
198→                    sourceSpaceId, migrationType, migrationConfig);
199→        }
200→
201→        log.info("Completed saving new node tree for space: {}", spaceId);
202→    }
