204→    private void saveNodeAndChildren(TreeNode<SpaceNodeVo> node, String spaceId, Map<String, String> nodeIdMapping,
205→                                      Long parentId, Long userId, String sourceSpaceId,
206→                                      MigrationTypeEnum migrationType, MigrationConfig migrationConfig) {
207→        SpaceNodeVo spaceNodeVo = node.getData();
208→        String oldNodeId = spaceNodeVo.getAppSpaceNodeId();
209→        String newNodeId = nodeIdMapping.get(oldNodeId);
210→
211→        if (Objects.equals(spaceNodeVo.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
212→            newNodeId = "";
213→        }
214→
215→        if (newNodeId == null) {
216→            log.error("No mapping found for node: {}", oldNodeId);
217→            return;
218→        }
219→
220→        SpaceNodeEntity spaceNodeEntity = SpaceNodeEntity.builder()
221→                .appSpaceNodeId(newNodeId)
222→                .name(spaceNodeVo.getName())
223→                .type(spaceNodeVo.getType())
224→                .appSpaceNodeId(newNodeId)
225→                .description(spaceNodeVo.getDescription())
226→                .spaceId(spaceId)
227→                .createdBy(userId)
228→                .updatedBy(userId)
229→                .build();
230→
231→        spaceNodeService.save(spaceNodeEntity);
232→        NodeEntity nodeEntity = treeNodeTemplate.addNode(parentId, spaceId, spaceNodeEntity.getId(), SpaceNodeEntity.class);
233→        log.info("migrate node, id: {}, appSpaceNodeId: {}, name: {}, parentId",spaceNodeEntity.getId(),spaceNodeEntity.getAppSpaceNodeId(),spaceNodeEntity.getName());
234→
235→        // 复制文件关联的版本快照
236→        copyVersionSnapshots(node.getRelId(), spaceNodeEntity, spaceId, sourceSpaceId, migrationType, migrationConfig);
237→
238→        if (node.getChildren() != null && !node.getChildren().isEmpty()) {
239→            for (TreeNode<SpaceNodeVo> child : node.getChildren()) {
240→                saveNodeAndChildren(child, spaceId, nodeIdMapping, nodeEntity.getId(), userId,
241→                        sourceSpaceId, migrationType, migrationConfig);
242→            }
243→        }
244→    }
