246→    /**
247→     * 迁移文件时，复制其关联的历史版本快照
248→     */
249→    private void copyVersionSnapshots(Long originalNodeId, SpaceNodeEntity newSpaceNodeEntity,
250→                                       String targetSpaceId, String sourceSpaceId,
251→                                       MigrationTypeEnum migrationType, MigrationConfig migrationConfig) {
252→        // 文件夹没有版本快照
253→        if (Objects.equals(newSpaceNodeEntity.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
254→            return;
255→        }
256→
257→        List<CollabspaceVersionSnapshotEntity> snapshots = versionSnapshotService.getByNodeId(
258→                originalNodeId, VersionSnapshotStatusEnum.ENABLED.getValue());
259→        if (snapshots.isEmpty()) {
260→            return;
261→        }
262→
263→        log.info("copyVersionSnapshots: originalNodeId={}, newNodeId={}, snapshotCount={}",
264→                originalNodeId, newSpaceNodeEntity.getId(), snapshots.size());
265→
266→        for (CollabspaceVersionSnapshotEntity snapshot : snapshots) {
267→            try {
268→                SpaceNodeVo snapshotNodeVo = new SpaceNodeVo();
269→                snapshotNodeVo.setAppSpaceNodeId(snapshot.getSnapshotId());
270→                snapshotNodeVo.setType(newSpaceNodeEntity.getType());
271→                snapshotNodeVo.setName(snapshot.getSnapshotName());
272→
273→                TreeNode<SpaceNodeVo> snapshotTreeNode = new TreeNode<>();
274→                snapshotTreeNode.setData(snapshotNodeVo);
275→
276→                List<TreeNode<SpaceNodeVo>> snapshotTree = new ArrayList<>();
277→                snapshotTree.add(snapshotTreeNode);
278→
279→                SpaceNodeMigrationResult result = appMigrationChain.executeMigration(
280→                        snapshotTree, targetSpaceId, sourceSpaceId, migrationType, migrationConfig);
281→
282→                if (result.getErrorMessage() != null) {
283→                    log.warn("copyVersionSnapshots: failed to copy snapshot file, originalNodeId={}, snapshotId={}, error={}",
284→                            originalNodeId, snapshot.getSnapshotId(), result.getErrorMessage());
285→                    continue;
286→                }
287→
288→                String newSnapshotFileId = result.getNodeIdMapping().get(snapshot.getSnapshotId());
289→                if (newSnapshotFileId == null) {
290→                    log.warn("copyVersionSnapshots: no mapping for snapshotId={}", snapshot.getSnapshotId());
291→                    continue;
292→                }
293→
294→                CollabspaceVersionSnapshotEntity newSnapshot = CollabspaceVersionSnapshotEntity.builder()
295→                        .nodeId(newSpaceNodeEntity.getId())
296→                        .snapshotId(newSnapshotFileId)
297→                        .snapshotName(snapshot.getSnapshotName())
298→                        .snapshotStatus(VersionSnapshotStatusEnum.ENABLED.getValue())
299→                        .operatorId(0L)
300→                        .build();
301→                versionSnapshotService.save(newSnapshot);
302→
303→                SpaceNodeEntity snapshotSpaceNode = SpaceNodeEntity.builder()
304→                        .appSpaceNodeId(newSnapshotFileId)
305→                        .name(snapshot.getSnapshotName())
306→                        .type(newSpaceNodeEntity.getType())
307→                        .description("")
308→                        .spaceId(targetSpaceId)
309→                        .createdBy(newSpaceNodeEntity.getCreatedBy())
310→                        .updatedBy(newSpaceNodeEntity.getUpdatedBy())
311→                        .isSnapshot(SpaceNodeSnapshotEnum.SNAPSHOT.getValue())
312→                        .build();
313→                spaceNodeService.save(snapshotSpaceNode);
314→
315→                log.info("copyVersionSnapshots: copied snapshot, originalSnapshotId={}, newSnapshotId={}, newNodeId={}",
316→                        snapshot.getSnapshotId(), newSnapshotFileId, newSpaceNodeEntity.getId());
317→
318→            } catch (Exception e) {
319→                log.error("copyVersionSnapshots: failed to copy snapshot, originalNodeId={}, snapshotId={}, error={}",
320→                        originalNodeId, snapshot.getSnapshotId(), e.getMessage(), e);
321→            }
322→        }
323→    }
