325→    private List<TreeNode<SpaceNodeVo>> deserializeTree(String json) throws IOException {
326→        ObjectMapper mapper = objectMapper.copy();
327→        mapper.addMixIn(TreeNode.class, TreeNodeMixin.class);
328→        SimpleModule module = new SimpleModule();
329→        module.addAbstractTypeMapping(RelIdProvider.class, SpaceNodeVo.class);
330→        mapper.registerModule(module);
331→        JavaType treeNodeType =
332→                mapper.getTypeFactory().constructParametricType(TreeNode.class, SpaceNodeVo.class);
333→        JavaType listType =
334→                mapper.getTypeFactory().constructCollectionType(List.class, treeNodeType);
335→        return mapper.readValue(json, listType);
336→    }
