112→    public List<VersionSnapshotVo> listVersionSnapshot(Long spaceNodeId, Integer status) {
113→        List<CollabspaceVersionSnapshotEntity> list = versionSnapshotService.getByNodeId(spaceNodeId, status);
114→        if (list.isEmpty()){
115→            return new ArrayList<>();
116→        }
117→        List<Long> creatorList = new ArrayList<>(list.stream().map(CollabspaceVersionSnapshotEntity::getCreatedBy).toList());
118→        List<Long> operatorList = list.stream().map(CollabspaceVersionSnapshotEntity::getOperatorId).toList();
119→        if (!operatorList.isEmpty()){
120→            creatorList.addAll(operatorList);
121→        }
122→        creatorList = creatorList.stream().filter(o -> o != null && o != 0L).toList();
123→        List<UserSimpleInfoVo> userList = apitableGrpcClientService.getUserByIds(creatorList);
124→        List<VersionSnapshotVo> voList = new ArrayList<>();
125→        list.forEach(item -> {
126→            Long userId = item.getOperatorId();
127→            UserSimpleInfoVo operator = userList.stream().filter(o -> Objects.equals(o.getId(), userId)).findFirst().orElse(null);
128→            UserSimpleInfoVo creator = userList.stream().filter(o -> Objects.equals(o.getId(), item.getCreatedBy())).findFirst().orElse(null);
129→            String opUserName = operator == null ? "" : operator.getNickName();
130→            String createUserName = creator == null ? "" : creator.getNickName();
131→            String deleteTime = status.equals(VersionSnapshotStatusEnum.DISABLED.getValue()) ?
132→                    item.getUpdatedAt().toString() : "";
133→            voList.add(VersionSnapshotVo.builder().snapshotName(item.getSnapshotName()).id(item.getId().toString())
134→                    .snapshotId(item.getSnapshotId()).snapshotCreator(createUserName).
135→                    snapshotDeleteUser(opUserName).snapshotCreateTime(item.getCreatedAt().toString()).
136→                    snapshotDeleteTime(deleteTime).build());
137→        });
138→        List<VersionSnapshotVo> finalList = voList;
139→        finalList = finalList.stream().sorted(Comparator.comparing(VersionSnapshotVo::getSnapshotCreateTime)).toList();
140→        return finalList;
141→    }
