100→    @Override
101→    public String createMigrationTask(List<Long> spaceNodeIds, String targetSpaceId, String sourceSpaceId, Long userId, Boolean isRemained) {
102→        UserSimpleInfoVo user = apitableGrpcClientService.getUserById(userId);
103→        String email = user.getEmail();
104→        Set<Long> targetNodeIds = new HashSet<>(spaceNodeIds);
105→        // 为了尽量保持原 spaceNodeTree 的相对顺序, 直接拉整个树再筛选
106→        List<TreeNode<SpaceNodeVo>> spaceNodeTreeOrigin = spaceNodeQueryManager.getSpaceNodeTree(sourceSpaceId);
107→        List<TreeNode<SpaceNodeVo>> spaceNodeTree = TreeUtil.filterByRelIds(spaceNodeTreeOrigin, targetNodeIds);
108→        List<SpaceAppRelVo> sourceSpaceApps = spaceAppRelService.listBySpaceId(sourceSpaceId).stream().map(SpaceAppRelVo::new).toList();
109→
110→        // 目前每个服务都只会执行一种迁移逻辑, MigrationTypeEnum直接由服务环境判断, mirror服务只执行跨服务器迁移, 其它的都是服务器内迁移
111→        String taskId;
112→        if (constProperties.isMirror()) {
113→            taskId = collabspaceGrpcClientService.createSpaceNodeMigrationTask(spaceNodeTree, email, targetSpaceId, sourceSpaceId, sourceSpaceApps);
114→        } else {
115→            taskId = acceptMigrationTask(spaceNodeTree, email, targetSpaceId, sourceSpaceId, sourceSpaceApps,
116→                    MigrationTypeEnum.INTRA_SERVER.getValue(), isRemained);
117→        }
118→
119→        log.info("createMigrationTask: taskId={}, sourceNodeIds={}, targetSpaceId={}, sourceSpaceId={}, userId={}, filteredTreeSize={}",
120→                taskId, spaceNodeIds, targetSpaceId, sourceSpaceId, userId, spaceNodeTree.size());
121→
122→        return taskId;
123→    }
