125→    @Override
126→    public String createBatchMigrationTask(List<BatchMigrationItem> items,
127→                                           String targetSpaceId, Long userId, Boolean isRemained) {
128→        String batchId = "batch-" + System.currentTimeMillis() + "-" + UUID.randomUUID().toString().substring(0, 6);
129→
130→        for (BatchMigrationItem item : items) {
131→            String sourceSpaceId = item.getSourceSpaceId();
132→            List<Long> spaceNodeIds = item.getSpaceNodeIds();
133→
134→            UserSimpleInfoVo user = apitableGrpcClientService.getUserById(userId);
135→            String email = user.getEmail();
136→            Set<Long> targetNodeIds = new HashSet<>(spaceNodeIds);
137→
138→            List<TreeNode<SpaceNodeVo>> spaceNodeTreeOrigin = spaceNodeQueryManager.getSpaceNodeTree(sourceSpaceId);
139→            List<TreeNode<SpaceNodeVo>> spaceNodeTree = TreeUtil.filterByRelIds(spaceNodeTreeOrigin, targetNodeIds);
140→            List<SpaceAppRelVo> sourceSpaceApps = spaceAppRelService.listBySpaceId(sourceSpaceId).stream()
141→                    .map(SpaceAppRelVo::new).toList();
142→
143→            if (isRemained == null) {
144→                isRemained = true;
145→            }
146→
147→            String taskId = acceptMigrationTask(spaceNodeTree, email, targetSpaceId, sourceSpaceId, sourceSpaceApps,
148→                    MigrationTypeEnum.INTRA_SERVER.getValue(), isRemained);
149→
150→            // 更新子任务的 batchId
151→            SpaceNodeMigrationTaskEntity task = spaceNodeMigrationTaskService.getByTaskId(taskId);
152→            task.setBatchId(batchId);
153→            spaceNodeMigrationTaskService.updateById(task);
154→
155→            log.info("createBatchMigrationTask: batchId={}, taskId={}, sourceSpaceId={}, nodeCount={}",
156→                    batchId, taskId, sourceSpaceId, spaceNodeIds.size());
157→        }
158→
159→        return batchId;
160→    }
