162→    @Override
163→    public String acceptMigrationTask(List<TreeNode<SpaceNodeVo>> spaceNodeTree, String email, String targetSpaceId,
164→                                      String sourceSpaceId, List<SpaceAppRelVo> appRels, Integer migrationType, Boolean isRemained) {
165→        if (CollectionUtils.isEmpty(spaceNodeTree) || StringUtils.isBlank(targetSpaceId) || StringUtils.isBlank(email) || StringUtils.isBlank(sourceSpaceId)) {
166→            log.error("email={}, targetSpaceId={}, sourceSpaceId={}", email, targetSpaceId, sourceSpaceId);
167→            throw new BusinessException("acceptMigrationTask: empty or invalid arguments");
168→        }
169→
170→        String taskId = sourceSpaceId + "-" + targetSpaceId + "-" + System.currentTimeMillis();
171→
172→        SpaceNodeMigrationTaskEntity spaceNodeMigrationTaskEntity = SpaceNodeMigrationTaskEntity.builder()
173→                .taskId(taskId)
174→                .sourceSpaceId(sourceSpaceId)
175→                .targetSpaceId(targetSpaceId)
176→                .email(email)
177→                .originTree(JSONUtil.toJsonStr(spaceNodeTree))
178→                .sourceSpaceAppRels(JSONUtil.toJsonStr(appRels))
179→                .status(SpaceNodeMigrationTaskStatusEnum.PENDING.getValue())
180→                .type(migrationType)
181→                .isRemained(isRemained)
182→                .build();
183→        spaceNodeMigrationTaskService.save(spaceNodeMigrationTaskEntity);
184→
185→        SpaceNodeMigrationMessage message = SpaceNodeMigrationMessage.builder()
186→                .taskId(taskId)
187→                .build();
188→        rabbitMqSender.directSend(SPACE_NODE_MIGRATION_EXCHANGE, SPACE_NODE_MIGRATION_KEY, JSONUtil.toJsonStr(message));
189→
190→        log.info("acceptMigrationTask: taskId={}, email={}, targetSpaceId={}, sourceSpaceId={}, treeSize={}",
191→                taskId, email, targetSpaceId, sourceSpaceId, spaceNodeTree.size());
192→
193→        return taskId;
194→    }
