197→    public List<CopyFileVo> copyFile(List<Long> spaceNodeIds, Long userId, String sourceSpaceId, String targetSpaceId) {
198→        List<CopyFileVo> copyFileVoList = new ArrayList<>();
199→        Set<Long> targetNodeIds = new HashSet<>(spaceNodeIds);
200→        // 为了尽量保持原 spaceNodeTree 的相对顺序, 直接拉整个树再筛选
201→        List<TreeNode<SpaceNodeVo>> spaceNodeTreeOrigin = spaceNodeQueryManager.getSpaceNodeTreeWithoutRole(sourceSpaceId);
202→        List<TreeNode<SpaceNodeVo>> spaceNodeTree = TreeUtil.filterByRelIds(spaceNodeTreeOrigin, targetNodeIds);
203→
204→        checkCopy(spaceNodeTree, targetSpaceId);
205→
206→        MigrationTypeEnum migrationType = MigrationTypeEnum.fromValue(MigrationTypeEnum.INTRA_SERVER.getValue());
207→
208→        UserSimpleInfoVo user = apitableGrpcClientService.getUserById(userId);
209→        String email = user.getEmail();
210→
211→        MigrationConfig migrationConfig = MigrationConfig.builder()
212→                .email(email)
213→                .build();
214→
215→        SpaceNodeMigrationResult overallResult = appMigrationChain.executeMigration(
216→                spaceNodeTree,
217→                targetSpaceId,
218→                sourceSpaceId,
219→                migrationType,
220→                migrationConfig
221→        );
222→
223→        // 迁移中遇到错误抛异常并终止迁移
224→        if (overallResult.getErrorMessage() != null) {
225→            log.warn("Migration had errors: {}", overallResult.getErrorMessage());
226→            throw new BusinessException(overallResult.getErrorMessage());
227→        }
228→
229→        // 迁移后的节点重新构建成树并入库
230→        saveNewNodeTree(spaceNodeTree, targetSpaceId, overallResult.getNodeIdMapping(), userId,
231→                sourceSpaceId, migrationType, migrationConfig);
