238→            spaceNodeEntityList.stream().filter(o -> o.getAppSpaceNodeId().equals(v)).
239→                    findFirst().ifPresent(spaceNodeEntity -> vo.setAioSpaceNodeId(spaceNodeEntity.getId().toString()));
240→            copyFileVoList.add(vo);
241→
242→        });
243→        return copyFileVoList;
244→    }
