375→    private void saveNewNodeTree(List<TreeNode<SpaceNodeVo>> originalTree, String spaceId,
376→                                 Map<String, String> nodeIdMapping, Long userId,
377→                                 String sourceSpaceId, MigrationTypeEnum migrationType, MigrationConfig migrationConfig) {
378→        if (originalTree == null || originalTree.isEmpty()) {
379→            log.info("No tree nodes to save for space: {}", spaceId);
380→            return;
381→        }
382→
383→        log.info("Starting to save new node tree for space: {}, total original nodes: {}", spaceId, originalTree.size());
384→
385→        for (TreeNode<SpaceNodeVo> node : originalTree) {
386→            Long parentId = ROOT_PARENT_ID;
387→            if (spaceId.equals(node.getData().getSpaceId())) {
