@Override
public BatchMigrationTaskVo getBatchMigrationTaskInfo(String batchId) {
    List<SpaceNodeMigrationTaskEntity> tasks = spaceNodeMigrationTaskService.listByBatchId(batchId);
    if (tasks.isEmpty()) {
        return BatchMigrationTaskVo.builder().batchId(batchId).tasks(List.of()).build();
    }

    // 批量查询空间站名称，避免 N+1
    Set<String> spaceIds = tasks.stream().map(SpaceNodeMigrationTaskEntity::getSourceSpaceId).collect(Collectors.toSet());
    Map<String, String> spaceNameMap = new HashMap<>();
    for (String spaceId : spaceIds) {
        try {
            com.yottastudios.ns.collabspace.space.entity.SpaceEntity space = spaceService.getBySpaceId(spaceId);
            if (space != null) {
                spaceNameMap.put(spaceId, space.getName());
            }
        } catch (Exception e) {
            log.warn("Failed to get space name for spaceId={}, error={}", spaceId, e.getMessage());
        }
    }

    List<BatchMigrationSubTaskVo> subTasks = tasks.stream().map(task -> {
        String spaceName = spaceNameMap.getOrDefault(task.getSourceSpaceId(), "");
        return new BatchMigrationSubTaskVo(task, spaceName);
    }).toList();

    return BatchMigrationTaskVo.builder().batchId(batchId).tasks(subTasks).build();
}

